      "n": 43,
      "column": "left",
      "text": "Tad atgreesahs Josuüg /\\n wifs Israëls ar winnu / Leh-\\geri uhs Gilgalu."
    },
    {
      "n": 1,
      "column": "left",
      "text": "Ehz to / kad Jabins tas\\Kehnisch no Azora /\\Scho dsirdeja/ tad fuhtija\\winsch pee Jobabu to Kehnian\\no Madona/ un pee to Kehnian\\no Simrona/un pee to Kehnian\\no Afsawa."
    },
    {
      "n": 2,
      "column": "left",
      "text": "Un pee teem Kehnixeem /\\tas prett Seemeli Kalnôs un Klat-\\juna prett Deenas. Widdu Kin-\\nerot/ uu Eeleijas/ un eeksch Na-\\wot-Dor/ Juhr Mallá dsihwoja."
    },
    {
      "n": 3,
      "column": "left",
      "text": "Pee teem Kananitexeem\\prett Rihteem un Wakkara / un\\teem Amoritexeem / un Getite-\\xeem/ un teem Weresitexeem/ un\\teem Jebusitexeem Kalnôs / un\\teem Eewitexeem us appakschu\\pee Ermona tai Mizpas Seinê."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Schee tsgahje/ un wiſſi\\Raxxa-Pulki ar teem / un dands\\Laudis/ itt ka Smiltis / kas\\Juhr Mallá irr Pulká/ un war-\\ren dands Sirgu un Rattu."
    },
    {
      "n": 5,
      "column": "left",
      "text": "Wiſſi schee Kehnini ſapul-\\ſejahs/ un nahze/ un apmettehe\\Lehgerti kohpá / pee ta Meroma\\Uhdens/ karroht prett Israëlu."
    },
    {
      "n": 6,
      "column": "right",
      "text": "Un tas KUNGS fazzija\\us Josuü : Ne bihstees preekſch\\winneem/ jo rihtu ap scho Laiku/\\dohtchu es tohs wiſſus apkautus\\Israëta Preekscha / winno Sir-\\gus buhs tew tiſlus darriht / un\\winno Rattus ar Ugguni fade-\\dsinaht."
    },
    {
      "n": 7,
      "column": "right",
      "text": "Tad nahze Josuüs/ un wiſſi\\Raxxa-Wihri ar winnu peepe-\\ſchi pahr teem / pee ta Meroma\\Uhdens/ un uhssbrukke teem."
    },
    {
      "n": 8,
      "column": "right",
      "text": "Un tas KUNGS nodeewe\\tohs Israëta Rohká/ un tee kawe\\tohs/ un dsinnahs teem pakak\\lihds tam leelam Zihdonam / un\\lihds teem filteemi Uhdenim / un\\lihds tam Mizpas Klatjumam\\prett Rihteem/un kawe tohs / ka-\\mehrt ne weens no teem atlikke."
    },
    {
      "n": 9,
      "column": "right",
      "text": "Un Josuüs dartja teem /\\ittin ka tas KUNGS winnam\\bij fazzija / winno Sirgus dar-\\rija winsch tiſlus/un winno Rat-\\tus fadeosinaja winsch ar Ug-\\guni."
    },
    {
      "n": 10,
      "column": "right",
      "text": "Un Josuüs atgreesahs\\tanni Laiká/ un ubenehme Azoru/\\un winna Kehnianu fitte winsch\\ar Sohbimi / jo Azors bija pir-\\mak ta Galwa wisfo scho Kehni-\\au Walsiu."
    },
    {
      "n": 11,
      "column": "right",
      "text": "Un tee kawe wiſſus / kas\\eeksch ta ar Sohbina Asmini/\\winrus isdelddedami/ tur ne at-\\likke uweens/ kam Dwascha bi-\\ja/ un Azoru fadeosinaja winsch\\ar Ugguni."
    },
    {
      "n": 12,
      "column": "right",
      "text": "Un Josuüs usnehme wiſ-\\ſuscho Kehnianu Pilſſahtus / un\\wiſſus"
    }
  ],
